import React, { useState } from "react";
import Footer from "components/Footers/Footer.js";

export default function Profile() {
  const [showWorkerCV, setShowWorkerCV] = useState(false);
  const [showManagerCV, setShowManagerCV] = useState(false);
  const [workerStatus, setWorkerStatus] = useState("working");
  const [currentWorkPlace, setCurrentWorkPlace] = useState("Le Café Paris");
  const [workerInfo, setWorkerInfo] = useState({
    name: "Jenna Stones",
    role: "Développeuse Full Stack",
    experience: "5 ans d'expérience",
    skills: ["React.js", "Node.js", "Tailwind CSS", "Figma", "TypeScript", "MongoDB"],
    bio: "Développeuse passionnée avec une expertise en création d'applications web modernes. J'aime relever des défis techniques et créer des expériences utilisateur exceptionnelles. Certifiée AWS et Google Cloud.",
    email: "jenna.stones@example.com",
    phone: "+33 6 12 34 56 78",
    location: "Paris, France",
    languages: ["Français", "Anglais", "Espagnol"]
  });
  
  const [workHistory, setWorkHistory] = useState([
    { place: "Le Café Paris", role: "Développeuse Frontend", duration: "2023 - Présent", rating: 5, review: "Excellente développeuse, très professionnelle et ponctuelle. Un atout pour l'équipe !" },
    { place: "Tech Startup Lyon", role: "Développeuse Web", duration: "2021 - 2023", rating: 4, review: "Bon travail, équipe sympathique. Bonne progression." },
    { place: "Agence Digital", role: "Stagiaire Développeuse", duration: "2020 - 2021", rating: 4.5, review: "Apprentissage rapide, très motivée. Je recommande." }
  ]);
  
  const [currentRating, setCurrentRating] = useState(0);
  const [managerComment, setManagerComment] = useState("");
  
  const availablePlaces = [
    { id: 1, name: "Le Café Paris", location: "Paris", type: "Café", icon: "☕", color: "#FF6B6B" },
    { id: 2, name: "Restaurant La Mer", location: "Marseille", type: "Restaurant", icon: "🍽️", color: "#4ECDC4" },
    { id: 3, name: "Tech Hub Lyon", location: "Lyon", type: "Bureau", icon: "💻", color: "#45B7D1" },
    { id: 4, name: "Startup Factory", location: "Toulouse", type: "Coworking", icon: "🚀", color: "#F9CA24" }
  ];
  
  const [selectedPlace, setSelectedPlace] = useState(null);
  const [showPlaceSelector, setShowPlaceSelector] = useState(false);
  
  const addManagerReview = () => {
    if (currentRating > 0 && managerComment) {
      const newHistory = {
        place: currentWorkPlace,
        role: workerInfo.role,
        duration: new Date().toLocaleDateString('fr-FR'),
        rating: currentRating,
        review: managerComment
      };
      setWorkHistory([newHistory, ...workHistory]);
      setCurrentRating(0);
      setManagerComment("");
      alert("✅ Évaluation ajoutée avec succès !");
    } else {
      alert("⚠️ Veuillez sélectionner une note et ajouter un commentaire");
    }
  };
  
  const changeWorkPlace = (place) => {
    setCurrentWorkPlace(place.name);
    setSelectedPlace(place);
    setShowPlaceSelector(false);
    setWorkerStatus("working");
    alert(`✅ Lieu de travail changé : ${place.name} (${place.location})`);
  };
  
  const deactivateWorker = () => {
    setWorkerStatus("free");
    setCurrentWorkPlace("");
    alert("⚠️ Statut changé : En recherche d'emploi");
  };
  
  const activateWorker = () => {
    setShowPlaceSelector(true);
  };

  const brightStyle = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes shoot {
      0% { transform: translateX(0) translateY(0) rotate(45deg); opacity: 0; }
      5% { opacity: 1; }
      95% { opacity: 1; }
      100% { transform: translateX(-300px) translateY(300px) rotate(45deg); opacity: 0; }
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    @keyframes gradient {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes morph {
      0% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
      50% { border-radius: 30% 60% 70% 40% / 50% 60% 30% 60%; }
      100% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
    }
    
    @keyframes float {
      0%, 100% { transform: translateY(0px); }
      50% { transform: translateY(-10px); }
    }
    
    @keyframes glow {
      0%, 100% { box-shadow: 0 0 5px rgba(255,107,107,0.3); }
      50% { box-shadow: 0 0 25px rgba(255,107,107,0.6); }
    }
    
    @keyframes pulse {
      0%, 100% { transform: scale(1); }
      50% { transform: scale(1.05); }
    }
    
    .profile-hero-section {
      position: relative;
      background: linear-gradient(135deg, #667eea 0%, #764ba2 25%, #f093fb 50%, #f5576c 75%, #4facfe 100%);
      background-size: 400% 400%;
      animation: gradientShift 15s ease infinite;
      min-height: 100vh;
    }
    
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .shooting-star {
      position: absolute;
      width: 3px;
      height: 3px;
      background: linear-gradient(135deg, rgba(255,255,255,1) 0%, rgba(255,255,200,0.8) 100%);
      border-radius: 50%;
      opacity: 0;
      animation: shoot 2.5s ease-out infinite;
    }
    
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.8;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    .morphing-bg {
      width: 100%;
      max-width: 1100px;
      min-height: 420px;
      background: linear-gradient(45deg, #FF6B6B, #4ECDC4, #45B7D1, #F9CA24, #FF6B6B);
      background-size: 400% 400%;
      animation: gradient 10s ease infinite, morph 10s ease-in-out infinite;
      border-radius: 30px;
      transform-style: preserve-3d;
      box-shadow: 0 20px 40px rgba(0,0,0,0.2);
      border: 2px solid rgba(255,255,255,0.3);
      margin: 0 auto;
      padding: 90px 20px 30px 20px;
      position: relative;
      margin-top: 90px;
    }
    
    .image-wrapper {
      position: absolute;
      top: -90px;
      left: 50%;
      transform: translateX(-50%);
      z-index: 20;
    }
    
    .cards-container {
      display: flex;
      gap: 35px;
      justify-content: center;
      margin-top: 50px;
      flex-wrap: wrap;
    }
    
    .cv-card {
      flex: 1;
      min-width: 300px;
      background: linear-gradient(135deg, rgba(255,255,255,0.2), rgba(255,255,255,0.1));
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 35px 25px;
      cursor: pointer;
      transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      border: 1px solid rgba(255,255,255,0.4);
      text-align: center;
      animation: float 4s ease-in-out infinite;
    }
    
    .cv-card:hover {
      transform: translateY(-15px) scale(1.02);
      background: linear-gradient(135deg, rgba(255,255,255,0.3), rgba(255,255,255,0.2));
      border-color: #FF6B6B;
      box-shadow: 0 25px 50px rgba(255,107,107,0.3);
    }
    
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.85);
      backdrop-filter: blur(10px);
      z-index: 100;
      display: flex;
      align-items: center;
      justify-content: center;
      animation: fadeIn 0.3s ease;
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    .modal-content {
      background: linear-gradient(135deg, #2d1b4e, #1a0f2e);
      border-radius: 35px;
      padding: 35px;
      max-width: 650px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #FF6B6B;
      box-shadow: 0 0 40px rgba(255,107,107,0.3);
      animation: slideUp 0.4s ease;
    }
    
    @keyframes slideUp {
      from { transform: translateY(50px); opacity: 0; }
      to { transform: translateY(0); opacity: 1; }
    }
    
    .modal-content::-webkit-scrollbar {
      width: 6px;
    }
    
    .modal-content::-webkit-scrollbar-track {
      background: rgba(255,255,255,0.1);
      border-radius: 10px;
    }
    
    .modal-content::-webkit-scrollbar-thumb {
      background: #FF6B6B;
      border-radius: 10px;
    }
    
    .stars {
      display: flex;
      gap: 8px;
      justify-content: center;
      margin: 15px 0;
    }
    
    .rating-input {
      display: flex;
      gap: 10px;
      justify-content: center;
      margin: 10px 0;
    }
    
    .rating-star {
      font-size: 32px;
      cursor: pointer;
      color: #4a4a4a;
      transition: all 0.2s;
    }
    
    .rating-star:hover {
      transform: scale(1.2);
    }
    
    .rating-star.active {
      color: #F9CA24;
      text-shadow: 0 0 15px #F9CA24;
    }
    
    .work-history-item {
      background: linear-gradient(135deg, rgba(255,255,255,0.1), rgba(255,255,255,0.05));
      border-radius: 20px;
      padding: 18px;
      margin-bottom: 15px;
      transition: all 0.3s;
      border-left: 4px solid #FF6B6B;
    }
    
    .work-history-item:hover {
      background: linear-gradient(135deg, rgba(255,255,255,0.15), rgba(255,255,255,0.08));
      transform: translateX(5px);
    }
    
    .status-badge {
      display: inline-block;
      padding: 6px 15px;
      border-radius: 30px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 12px;
      animation: pulse 2s infinite;
    }
    
    .status-working {
      background: linear-gradient(135deg, #4ECDC4, #45B7D1);
      color: white;
    }
    
    .status-free {
      background: linear-gradient(135deg, #FF6B6B, #F5576C);
      color: white;
    }
    
    .place-selector {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 15px;
      margin-top: 20px;
    }
    
    .place-option {
      background: linear-gradient(135deg, rgba(78,205,196,0.2), rgba(69,183,209,0.1));
      border: 1px solid #4ECDC4;
      border-radius: 20px;
      padding: 18px;
      cursor: pointer;
      transition: all 0.3s;
      text-align: center;
    }
    
    .place-option:hover {
      background: linear-gradient(135deg, rgba(78,205,196,0.4), rgba(69,183,209,0.2));
      transform: scale(1.03);
      box-shadow: 0 10px 25px rgba(78,205,196,0.3);
    }
    
    .skill-tag {
      display: inline-block;
      padding: 5px 12px;
      background: linear-gradient(135deg, #4ECDC4, #45B7D1);
      border-radius: 20px;
      font-size: 12px;
      margin: 3px;
      color: white;
      font-weight: bold;
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #FF6B6B, #F5576C);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
    }
    
    .btn-primary:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 15px rgba(255,107,107,0.4);
    }
    
    .btn-success {
      background: linear-gradient(135deg, #4ECDC4, #45B7D1);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
    }
    
    .btn-success:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 15px rgba(78,205,196,0.4);
    }
    
    .btn-danger {
      background: linear-gradient(135deg, #FF6B6B, #F5576C);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
    }
    
    .btn-danger:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 15px rgba(255,107,107,0.4);
    }
    
    .profile-card {
      background: rgba(255,255,255,0.95);
      backdrop-filter: blur(10px);
      border-radius: 30px;
    }
    
    @media (max-width: 768px) {
      .morphing-bg {
        min-height: 500px;
        border-radius: 20px;
        padding: 75px 15px 25px 15px;
        margin-top: 75px;
      }
      .image-wrapper {
        top: -75px;
      }
      .cards-container {
        flex-direction: column;
        gap: 20px;
      }
      .cv-card {
        min-width: auto;
      }
    }
  `;

  return (
    <>
      <style>{brightStyle}</style>
      
      <div className="profile-hero-section" style={{ position: 'relative', minHeight: '100vh' }}>
        
        <div className="shooting-stars">
          {[...Array(80)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 4 + 1}px`,
              height: `${Math.random() * 4 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${Math.random() * 3 + 2}s`,
              background: `rgba(255,255,255,${Math.random() * 0.8 + 0.2})`
            }} />
          ))}
          {[...Array(12)].map((_, i) => (
            <div key={`shooting-${i}`} className="shooting-star" style={{
              left: `${Math.random() * 80 + 10}%`,
              top: `${Math.random() * 50}%`,
              width: `${Math.random() * 80 + 50}px`,
              height: '3px',
              animationDelay: `${Math.random() * 8}s`,
              animationDuration: `${Math.random() * 2 + 1.5}s`,
              transform: `rotate(${Math.random() * 60 + 30}deg)`,
              background: `linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(255,200,100,0.8) 50%, rgba(255,255,255,0) 100%)`
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "400px" }}>
            <div className="absolute top-0 w-full h-full bg-center bg-cover"
              style={{ backgroundImage: "url('https://images.pexels.com/photos/260922/pexels-photo-260922.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=2')" }}>
            </div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words profile-card w-full mb-6 shadow-2xl rounded-3xl -mt-48">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="relative">
                        <img alt="Jenna Stones" src="https://randomuser.me/api/portraits/women/68.jpg"
                          className="shadow-2xl rounded-full h-auto align-middle border-4 border-FF6B6B absolute -m-16 -ml-20 lg:-ml-16 max-w-150-px" />
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-3 lg:text-right lg:self-center">
                      <div className="py-6 px-3 mt-32 sm:mt-0">
                        <button className="btn-primary">📧 Contacter</button>
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-1">
                      <div className="flex justify-center py-4 lg:pt-4 pt-8 gap-6">
                        <div className="p-3 text-center bg-gradient-to-r from-FF6B6B/20 to-F5576C/20 rounded-2xl backdrop-blur-sm">
                          <span className="text-2xl font-bold block text-FF6B6B">156</span>
                          <span className="text-sm text-gray-600">Projets</span>
                        </div>
                        <div className="p-3 text-center bg-gradient-to-r from-4ECDC4/20 to-45B7D1/20 rounded-2xl backdrop-blur-sm">
                          <span className="text-2xl font-bold block text-4ECDC4">48</span>
                          <span className="text-sm text-gray-600">Clients</span>
                        </div>
                        <div className="p-3 text-center bg-gradient-to-r from-F9CA24/20 to-FF6B6B/20 rounded-2xl backdrop-blur-sm">
                          <span className="text-2xl font-bold block text-F9CA24">12</span>
                          <span className="text-sm text-gray-600">Récompenses</span>
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-bold leading-normal mb-2 text-gray-800">
                      {workerInfo.name}
                      <span className={`status-badge ${workerStatus === 'working' ? 'status-working' : 'status-free'}`}>
                        {workerStatus === 'working' ? '✅ En poste' : '📢 En recherche'}
                      </span>
                    </h3>
                    {workerStatus === 'working' && currentWorkPlace && (
                      <p className="text-md text-4ECDC4 font-semibold mt-2">
                        <i className="fas fa-building mr-2"></i>Travaille actuellement chez : <strong>{currentWorkPlace}</strong>
                      </p>
                    )}
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-500 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {workerInfo.location}
                    </div>
                    <div className="mb-2 text-gray-600 mt-10">
                      <i className="fas fa-briefcase mr-2 text-FF6B6B"></i>
                      <span className="font-semibold">{workerInfo.role}</span>
                    </div>
                  </div>
                  
                  <div className="cards-container">
                    <div className="cv-card" onClick={() => setShowWorkerCV(true)}>
                      <div className="text-7xl mb-4">📄✨</div>
                      <h3 className="text-2xl font-bold text-white mb-3">Mon CV</h3>
                      <p className="text-gray-200 text-sm leading-relaxed">Découvrez mon parcours professionnel, mes compétences techniques et mon expérience</p>
                      <div className="mt-5 text-4ECDC4 font-semibold flex items-center justify-center gap-2">
                        Voir le détail <span className="text-xl">→</span>
                      </div>
                    </div>
                    
                    <div className="cv-card" onClick={() => setShowManagerCV(true)}>
                      <div className="text-7xl mb-4">⭐🏆</div>
                      <h3 className="text-2xl font-bold text-white mb-3">Évaluations</h3>
                      <p className="text-gray-200 text-sm leading-relaxed">Historique des lieux de travail, évaluations et retours des managers</p>
                      <div className="mt-5 text-4ECDC4 font-semibold flex items-center justify-center gap-2">
                        Voir les avis <span className="text-xl">→</span>
                      </div>
                    </div>
                  </div>
                  
                  <div className="mt-12 py-10 border-t border-gray-200 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-700 italic">
                          "{workerInfo.bio}"
                        </p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {workerInfo.skills.map((skill, i) => (
                            <span key={i} className="skill-tag">{skill}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* Modal CV Personnel */}
      {showWorkerCV && (
        <div className="modal-overlay" onClick={() => setShowWorkerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowWorkerCV(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '28px', cursor: 'pointer', opacity: 0.7 }}>✕</button>
            <div style={{ textAlign: 'center' }}>
              <div className="text-7xl mb-4">👩‍💻🌟</div>
              <h2 className="text-3xl font-bold text-white mb-2">{workerInfo.name}</h2>
              <p className="text-4ECDC4 text-lg mb-4">{workerInfo.role}</p>
              
              <div className="text-left mt-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <h3 className="text-xl font-bold text-white mb-3 flex items-center gap-2">📋 Profil</h3>
                    <p className="text-gray-300 leading-relaxed">{workerInfo.bio}</p>
                  </div>
                  <div>
                    <h3 className="text-xl font-bold text-white mb-3 flex items-center gap-2">📞 Contact</h3>
                    <p className="text-gray-300">📧 {workerInfo.email}</p>
                    <p className="text-gray-300">📱 {workerInfo.phone}</p>
                    <p className="text-gray-300">📍 {workerInfo.location}</p>
                  </div>
                </div>
                
                <h3 className="text-xl font-bold text-white mt-5 mb-3 flex items-center gap-2">💪 Compétences</h3>
                <div className="flex flex-wrap gap-2">
                  {workerInfo.skills.map((skill, i) => (
                    <span key={i} className="skill-tag text-base">{skill}</span>
                  ))}
                </div>
                
                <h3 className="text-xl font-bold text-white mt-5 mb-3 flex items-center gap-2">🌍 Langues</h3>
                <div className="flex flex-wrap gap-2">
                  {workerInfo.languages.map((lang, i) => (
                    <span key={i} className="skill-tag text-base">{lang}</span>
                  ))}
                </div>
                
                <h3 className="text-xl font-bold text-white mt-5 mb-3 flex items-center gap-2">🎓 Expérience</h3>
                <p className="text-gray-300">{workerInfo.experience}</p>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {/* Modal Évaluations Manager */}
      {showManagerCV && (
        <div className="modal-overlay" onClick={() => setShowManagerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '750px' }}>
            <button onClick={() => setShowManagerCV(false)}
              style={{ float: 'right', background: 'none', border: 'none', color: 'white', fontSize: '28px', cursor: 'pointer', opacity: 0.7 }}>✕</button>
            <div>
              <div className="text-center">
                <div className="text-7xl mb-4">⭐👨‍💼</div>
                <h2 className="text-3xl font-bold text-white mb-2">Gestion des évaluations</h2>
                <p className="text-gray-400">Ajoutez des évaluations et gérez les périodes de travail</p>
              </div>
              
              <div style={{ background: 'linear-gradient(135deg, rgba(78,205,196,0.15), rgba(69,183,209,0.05))', borderRadius: '25px', padding: '25px', marginBottom: '25px', marginTop: '20px' }}>
                <h3 className="text-xl font-bold text-4ECDC4 mb-4 flex items-center gap-2">👨‍💼 Panel Manager</h3>
                <div className="mb-4">
                  <p className="text-white"><strong>📍 Lieu actuel :</strong> {currentWorkPlace || 'Non défini'}</p>
                </div>
                
                <div className="flex gap-3 flex-wrap mb-4">
                  {workerStatus !== 'working' && (
                    <button onClick={activateWorker} className="btn-success">✅ Activer le travailleur</button>
                  )}
                  {workerStatus === 'working' && (
                    <button onClick={deactivateWorker} className="btn-danger">🚫 Terminer la période</button>
                  )}
                </div>
                
                {showPlaceSelector && (
                  <div className="place-selector">
                    <h4 className="text-white text-center col-span-full mb-3">Choisissez un lieu de travail :</h4>
                    {availablePlaces.map(place => (
                      <div key={place.id} className="place-option" onClick={() => changeWorkPlace(place)}>
                        <div className="text-3xl mb-2">{place.icon}</div>
                        <div className="text-white font-bold">{place.name}</div>
                        <div className="text-gray-400 text-sm">{place.location}</div>
                        <div className="text-gray-500 text-xs mt-1">{place.type}</div>
                      </div>
                    ))}
                  </div>
                )}
                
                <div className="mt-5">
                  <label className="text-white font-semibold mb-2 block">⭐ Note (1 à 5 étoiles)</label>
                  <div className="rating-input">
                    {[1,2,3,4,5].map(star => (
                      <span key={star} className={`rating-star ${currentRating >= star ? 'active' : ''}`}
                        onClick={() => setCurrentRating(star)}>★</span>
                    ))}
                  </div>
                </div>
                <div className="mt-4">
                  <label className="text-white font-semibold mb-2 block">💬 Commentaire</label>
                  <textarea className="w-full p-3 rounded-xl mt-1 bg-white/10 text-white border border-4ECDC4/30 focus:outline-none focus:border-4ECDC4" rows="3"
                    value={managerComment} onChange={(e) => setManagerComment(e.target.value)}
                    placeholder="Écrivez votre commentaire ici..."></textarea>
                </div>
                <button onClick={addManagerReview} className="btn-primary w-full mt-4">
                  ✅ Ajouter l'évaluation
                </button>
              </div>
              
              <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">📋 Historique des évaluations</h3>
              {workHistory.map((work, index) => (
                <div key={index} className="work-history-item">
                  <div className="flex justify-between items-center flex-wrap mb-2">
                    <h4 className="text-white font-bold text-lg">{work.place}</h4>
                    <div className="stars">
                      {[...Array(5)].map((_, i) => (
                        <span key={i} style={{ color: i < work.rating ? '#F9CA24' : '#4a4a4a', fontSize: '18px' }}>★</span>
                      ))}
                    </div>
                  </div>
                  <p className="text-gray-300 text-sm">{work.role} • <span className="text-4ECDC4">{work.duration}</span></p>
                  <p className="text-gray-400 text-sm mt-2 italic">"{work.review}"</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
